"""
Bunge–Roothaan–Hartree–Fock atomic radial orbital database.

Coverage
--------
H (Z=1) — Kr (Z=36), i.e. periods 1–4. The original file shipped only with
H–Ar; coefficients for K (Z=19) through Kr (Z=36) were transcribed from the
same Bunge et al. (1993) tables (pages 127–144).

Citation
--------
C. F. Bunge, J. A. Barrientos, and A. V. Bunge,
"Roothaan–Hartree–Fock Ground-State Atomic Wave Functions: Slater-Type
Orbital Expansions and Expectation Values for Z = 2–54",
Atomic Data and Nuclear Data Tables 53, 113 (1993).

Data conventions
----------------
For each orbital, ``basis`` is a list of [n_basis, zeta, coefficient] triples.
The radial orbital is built as
    R(r) = sum_p  C_p * N_p * r^(n_p - 1) * exp(-zeta_p * r)
with the Slater-type primitive normalization
    N_p = ((2*zeta_p)^(2*n_p + 1) / (2*n_p)!)^(1/2).

The naming ``bunge_rhf_h_to_ar`` is kept for backward compatibility with
existing imports — the database itself now extends to Kr.
"""

from __future__ import annotations

from dataclasses import dataclass
from math import factorial
from typing import Dict, Tuple

import numpy as np
from scipy.special import sph_harm


@dataclass(frozen=True)
class BasisTerm:
    n_basis: int
    zeta: float
    coeff: float


@dataclass(frozen=True)
class OrbitalData:
    label: str
    l: int
    energy_hartree: float
    basis: Tuple[BasisTerm, ...]


@dataclass(frozen=True)
class ElementData:
    Z: int
    symbol: str
    name: str
    term_symbol: str
    configuration: str
    source: str
    orbitals: Dict[str, OrbitalData]


